// generar_229_celebraciones.js
// CHIQUI Entre Señales — Cumpleaños y "Se unió a tu familia" 🎂🏡
//
// IMPORTANTE: primero ejecuta sql_229_fecha_union.sql en Supabase
// (New snippet) — crea la columna fecha_union en mascotas.
//
// Qué hace este script:
// 1) components/CelebracionesMascota.tsx (NUEVO) → banners cálidos y
//    cerrables en el dashboard:
//    - HOY: tarjeta destacada con la ilustración especial de Chiqui
//      ("🎉 ¡Hoy Emma está de cumpleaños! Cumple 3 años." /
//       "❤️ ¡Hoy se cumplen 3 años desde que Emma se unió a tu familia!")
//    - PRÓXIMOS (hasta 7 días antes): banner sutil de una línea
//      ("🎈 Faltan 5 días para el cumpleaños de Emma." /
//       "🏡 En 5 días celebrarán un nuevo aniversario juntos.")
//    - Al tocarlo se cierra y queda cerrado para esa ocurrencia
//      (recordado por mascota + ocasión + año) — no invasivo.
//    - Catálogo EXTENSIBLE: Día del Perro / Día del Gato futuros se
//      agregan con una entrada más, sin tocar el render.
// 2) components/DashboardContenido.tsx → renderiza las celebraciones
//    bajo el selector de mascota.
// 3) app/perfil/page.tsx → campo "Se unió a tu familia" (FechaSelector)
//    editable y visible en la ficha. NO se agrega al onboarding, que
//    debe seguir rápido y básico.
// 4) public/chiqui/ → 8 ilustraciones nuevas de Chiqui (cumple,
//    familia, halloween, navidad, recordatorio, vet, felicidad de
//    racha, y versión nueva de amor) listas para esta y futuras
//    ocasiones. Por eso este script pesa más de lo habitual (~3 MB).
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_229_celebraciones.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/CelebracionesMascota.tsx",
    base64: ""
  },
  {
    ruta: "components/DashboardContenido.tsx",
    base64: ""
  },
  {
    ruta: "app/perfil/page.tsx",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_amor.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_cumple.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_familia.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_felicidad_racha.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_halloween.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_navidad.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_recordatorio.png",
    base64: ""
  },
  {
    ruta: "public/chiqui/chiqui_vet.png",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64')
    if (a.ruta.endsWith('.png')) {
      fs2.writeFileSync(rutaCompleta, contenido)
    } else {
      fs2.writeFileSync(rutaCompleta, contenido.toString('utf8'), 'utf8')
    }
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos de código + 8 imágenes escritos correctamente.')
  console.log('Recuerda: el SQL va primero. Luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
